<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>Bouncing Ball Physics Playground</title>
<style>
  * { margin: 0; padding: 0; box-sizing: border-box; }
  body {
    background: #0f0f13;
    color: #e0e0e0;
    font-family: system-ui, sans-serif;
    display: flex;
    flex-direction: column;
    align-items: center;
    justify-content: center;
    min-height: 100vh;
    gap: 16px;
  }
  h1 {
    font-size: 1.4rem;
    font-weight: 600;
    color: #a0c4ff;
    letter-spacing: 0.05em;
  }
  #sim {
    display: block;
    border: 2px solid #2a2a3e;
    border-radius: 8px;
    cursor: crosshair;
    box-shadow: 0 0 32px rgba(100, 120, 255, 0.15);
  }
  .controls {
    display: flex;
    gap: 12px;
  }
  button {
    padding: 10px 24px;
    border: none;
    border-radius: 6px;
    font-size: 0.95rem;
    font-weight: 600;
    cursor: pointer;
    transition: filter 0.15s, transform 0.1s;
  }
  button:hover { filter: brightness(1.15); }
  button:active { transform: scale(0.96); }
  #drop { background: #4c6ef5; color: #fff; }
  #play { background: #37b24d; color: #fff; }
  #clear { background: #f03e3e; color: #fff; }
  #play.paused { background: #f59f00; }
  .info {
    font-size: 0.8rem;
    color: #666;
  }
</style>
</head>
<body>
<h1>Bouncing Ball Playground</h1>
<canvas id="sim" width="600" height="500"></canvas>
<div class="controls">
  <button id="drop">Drop Ball</button>
  <button id="play">Pause</button>
  <button id="clear">Clear</button>
</div>
<div class="info">Click canvas to add a ball anywhere</div>

<script>
(function() {
  const canvas = document.getElementById('sim');
  const ctx = canvas.getContext('2d');
  const W = canvas.width;
  const H = canvas.height;

  const GRAVITY = 0.4;
  const RESTITUTION = 0.78;
  const MIN_R = 10;
  const MAX_R = 28;

  const COLORS = [
    '#4c6ef5','#f03e3e','#37b24d','#f59f00',
    '#ae3ec9','#1098ad','#f76707','#74c0fc',
    '#a9e34b','#ff8787',
  ];

  let ballList = [];
  let running = true;
  let animId = null;
  let colorIdx = 0;

  function randomR() {
    return MIN_R + Math.random() * (MAX_R - MIN_R);
  }

  function nextColor() {
    return COLORS[colorIdx++ % COLORS.length];
  }

  function addBall(x, y, vx = 0, vy = 0, r) {
    if (r == null) r = randomR();
    r = Math.max(1, r);
    // clamp starting position inside canvas
    x = Math.max(r, Math.min(W - r, x));
    y = Math.max(r, Math.min(H - r, y));
    ballList.push({ x, y, vx, vy, r, color: nextColor() });
  }

  function clear() {
    ballList = [];
  }

  function step(dt = 1) {
    for (const b of ballList) {
      b.vy += GRAVITY * dt;
      b.x += b.vx * dt;
      b.y += b.vy * dt;

      // floor
      if (b.y + b.r >= H) {
        b.y = H - b.r;
        b.vy = -Math.abs(b.vy) * RESTITUTION;
        if (Math.abs(b.vy) < 0.5) b.vy = 0;
      }
      // ceiling
      if (b.y - b.r <= 0) {
        b.y = b.r;
        b.vy = Math.abs(b.vy) * RESTITUTION;
      }
      // right wall
      if (b.x + b.r >= W) {
        b.x = W - b.r;
        b.vx = -Math.abs(b.vx) * RESTITUTION;
      }
      // left wall
      if (b.x - b.r <= 0) {
        b.x = b.r;
        b.vx = Math.abs(b.vx) * RESTITUTION;
      }
    }
    draw();
  }

  function draw() {
    ctx.clearRect(0, 0, W, H);

    // background
    ctx.fillStyle = '#12121a';
    ctx.fillRect(0, 0, W, H);

    // subtle grid
    ctx.strokeStyle = 'rgba(255,255,255,0.03)';
    ctx.lineWidth = 1;
    for (let x = 0; x <= W; x += 50) {
      ctx.beginPath(); ctx.moveTo(x, 0); ctx.lineTo(x, H); ctx.stroke();
    }
    for (let y = 0; y <= H; y += 50) {
      ctx.beginPath(); ctx.moveTo(0, y); ctx.lineTo(W, y); ctx.stroke();
    }

    for (const b of ballList) {
      // glow
      const grd = ctx.createRadialGradient(b.x - b.r * 0.3, b.y - b.r * 0.3, b.r * 0.1, b.x, b.y, b.r);
      grd.addColorStop(0, lighten(b.color, 0.5));
      grd.addColorStop(1, b.color);

      ctx.beginPath();
      ctx.arc(b.x, b.y, b.r, 0, Math.PI * 2);
      ctx.fillStyle = grd;
      ctx.fill();

      // shine
      ctx.beginPath();
      ctx.arc(b.x - b.r * 0.3, b.y - b.r * 0.3, b.r * 0.25, 0, Math.PI * 2);
      ctx.fillStyle = 'rgba(255,255,255,0.25)';
      ctx.fill();
    }

    // ball count
    ctx.fillStyle = 'rgba(255,255,255,0.25)';
    ctx.font = '12px system-ui';
    ctx.fillText(`${ballList.length} ball${ballList.length !== 1 ? 's' : ''}`, 8, 18);
  }

  function lighten(hex, amount) {
    const n = parseInt(hex.slice(1), 16);
    const r = Math.min(255, ((n >> 16) & 0xff) + Math.round(255 * amount));
    const g = Math.min(255, ((n >> 8) & 0xff) + Math.round(255 * amount));
    const bv = Math.min(255, (n & 0xff) + Math.round(255 * amount));
    return `rgb(${r},${g},${bv})`;
  }

  function loop() {
    if (running) {
      step(1);
    }
    animId = requestAnimationFrame(loop);
  }

  // controls
  document.getElementById('drop').addEventListener('click', () => {
    const x = W / 2 + (Math.random() - 0.5) * 100;
    addBall(x, 40, (Math.random() - 0.5) * 4, 0);
  });

  document.getElementById('play').addEventListener('click', function() {
    running = !running;
    this.textContent = running ? 'Pause' : 'Play';
    this.classList.toggle('paused', !running);
  });

  document.getElementById('clear').addEventListener('click', () => {
    clear();
    draw();
  });

  canvas.addEventListener('click', (e) => {
    const rect = canvas.getBoundingClientRect();
    const scaleX = W / rect.width;
    const scaleY = H / rect.height;
    const x = (e.clientX - rect.left) * scaleX;
    const y = (e.clientY - rect.top) * scaleY;
    addBall(x, y, (Math.random() - 0.5) * 6, (Math.random() - 0.5) * 2);
  });

  // public API
  window.sim = {
    get w() { return W; },
    get h() { return H; },
    balls() {
      return ballList.map(b => ({ x: b.x, y: b.y, vx: b.vx, vy: b.vy, r: b.r }));
    },
    addBall,
    clear,
    step,
  };

  // seed a few balls
  addBall(W * 0.3, 80, 2, 0, 18);
  addBall(W * 0.6, 60, -3, 0, 22);
  addBall(W * 0.5, 40, 0, 0, 14);

  loop();
})();
</script>
</body>
</html>
